pm.visualizer.set(template, { image: base64Image });

// 解析响应体
const jsonData = pm.response.json();

// 原始字段位置（保留你的原始取法）
const rawImage = jsonData?.choices?.[0]?.message?.images?.[0]?.image_url?.url;

if (!rawImage) {
    pm.visualizer.set("<h3 style='color:red;'>未找到 b64_json 字段或 image_url</h3>");
    return;
}

/*
  下面的处理逻辑用于：
  - 检测 rawImage 是 data URI / http URL / 还是纯 base64 字符串
  - 统一得到：cleanedBase64（没有 data: 前缀的 base64 内容，若不可用则为 null）
             imgSrc（用于 <img> 的 src，可为 data URI 或外部 URL）
*/
let isDataUri = typeof rawImage === "string" && rawImage.startsWith("data:");
let isHttpUrl = typeof rawImage === "string" && /^https?:\/\//i.test(rawImage);
let cleanedBase64 = null;
let imgSrc = null;

if (isDataUri) {
    // 如果已经包含 data:image/... 前缀，拆分出 base64 内容（逗号后面）
    // <u><b><i>修改：当 raw 为 data URI 时不再在模板里重复拼接 data:image 前缀，直接使用原始 rawImage 作为 imgSrc</i></b></u>
    const parts = rawImage.split(",");
    cleanedBase64 = parts.length > 1 ? parts.slice(1).join(",") : null; // 有可能 header 里包含逗号（防御性写法）
    imgSrc = rawImage; // 保持原始 data URI，用于 <img>
} else if (isHttpUrl) {
    // 外部 URL：无法直接把外部图片放到 Base64 文本域（除非去 fetch 转换），这里只展示图片并提示没有 base64
    cleanedBase64 = null;
    imgSrc = rawImage;
} else {
    // 既不是 data URI 也不是 http URL，那么我们认为它可能就是纯 base64 字符串
    // <u><b><i>修改：支持纯 base64 字符串（没有 data: 前缀）——渲染时拼接 data:image/png;base64,</i></b></u>
    cleanedBase64 = rawImage;
    imgSrc = "data:image/png;base64," + cleanedBase64;
}

// 可视化模板：展示图片、Base64 文本（若有）、分辨率和比例
const template = `
<div style="font-family: sans-serif; padding: 20px;">
    <h2>生成的图片</h2>

    <div style="display:flex; gap:18px; align-items:flex-start;">
      <div>
        <img id="generatedImg"
             src="{{imgSrc}}"
             alt="generated image"
             style="max-width: 420px; max-height: 420px; display: block; border:1px solid #eee; padding:4px;" />
        <div id="meta" style="margin-top:8px; font-size:13px; color:#333;">
          <!-- 分辨率和比例占位 -->
          <div id="resolution">分辨率：<span id="resVal">加载中...</span></div>
          <div id="ratio" style="margin-top:4px;">宽高比：<span id="ratioVal">-</span></div>
        </div>
      </div>

      <div style="flex:1; min-width:320px;">
        <h3 style="margin-top:0;">Base64 内容</h3>
        <textarea id="b64Text"
                  style="width: 100%; height: 200px; padding: 10px; font-size: 12px; white-space:pre-wrap;">{{base64Text}}</textarea>

        <div style="margin-top: 12px; display: flex; gap: 10px; align-items:center;">
            <!-- 复制 Base64 -->
            <button id="copyBase64Btn"
                style="padding: 8px 16px; background:#007bff; color:#fff; border:none; border-radius:4px; cursor:pointer; transition:0.2s;">
                一键复制 Base64
            </button>

            <!-- 下载图片 -->
            <a id="downloadBtn"
               download="image.png"
               style="padding: 8px 16px; background:#28a745; color:#fff; border:none; border-radius:4px; cursor:pointer; text-decoration:none; line-height:26px;">
                下载图片
            </a>

            <span id="note" style="margin-left:8px; color:#666; font-size:12px;"></span>
        </div>
      </div>
    </div>

    <script>
        // 辅助：视觉成功提示
        function showSuccess(button, originalText) {
            button.style.background = "#17a2b8";     // 变为蓝绿色
            button.textContent = "复制成功 ✓";       

            setTimeout(() => {
                button.style.background = "";          // 恢复原样
                button.textContent = originalText;     // 恢复原按钮文字
            }, 1500);
        }

        // 复制 Base64 按钮逻辑
        document.getElementById("copyBase64Btn").onclick = function () {
            const btn = this;
            const textArea = document.getElementById("b64Text");

            // 如果 textarea 为空则提示并返回
            if (!textArea.value) {
                btn.textContent = "无 Base64 可复制";
                setTimeout(() => btn.textContent = "一键复制 Base64", 1500);
                return;
            }

            textArea.select();
            try {
                document.execCommand("copy");
                showSuccess(btn, "一键复制 Base64");
            } catch (e) {
                btn.textContent = "复制失败";
                setTimeout(() => btn.textContent = "一键复制 Base64", 1500);
            }
        };

        // 下载图片按钮设置（如果我们有 base64，则使用 data URI，否则使用 img 的 src）
        (function setupDownload() {
            const downloadBtn = document.getElementById("downloadBtn");
            const b64 = document.getElementById("b64Text").value.trim();
            const imgEl = document.getElementById("generatedImg");

            if (b64) {
                // <u><b><i>修改：如果 textarea 中有纯 base64 内容，拼接 data: 前缀作为下载链接；如果 textarea 为空但 img 是 data URI，则使用 img.src</i></b></u>
                // textarea 中的内容我们认为是无前缀的 base64（模板中已经处理），但也做防御：若用户粘贴了带前缀的，先检查。
                if (/^data:/i.test(b64)) {
                    downloadBtn.href = b64;
                } else {
                    downloadBtn.href = "data:image/png;base64," + b64;
                }
                document.getElementById("note").textContent = "（已使用 Base64 提供下载）";
            } else {
                // 没有 base64 文本：把 img 的 src 用作下载（如果是外部 URL，浏览器可能直接跳转或另存；若浏览器阻止跨域另存，用户可右键图片另存）
                downloadBtn.href = imgEl.src || "";
                document.getElementById("note").textContent = imgEl.src && imgEl.src.startsWith("data:") ? "（使用 data URI 下载）" : "（外部 URL：右键图片另存）";
            }
        })();

        // 读取图片分辨率与宽高比（在图片加载完成后）
        (function showImageMeta() {
            const img = document.getElementById("generatedImg");
            const resVal = document.getElementById("resVal");
            const ratioVal = document.getElementById("ratioVal");

            function updateMeta() {
                // naturalWidth / naturalHeight 在图片加载完成后可用
                if (img.naturalWidth && img.naturalHeight) {
                    resVal.textContent = img.naturalWidth + " × " + img.naturalHeight + " px";
                    // 计算最简宽高比，例如 16:9，先算小数再化为近似分子分母
                    const gcd = (a, b) => b === 0 ? a : gcd(b, a % b);
                    const w = img.naturalWidth;
                    const h = img.naturalHeight;
                    const g = gcd(w, h);
                    ratioVal.textContent = (w/g) + ":" + (h/g) + " (" + ( (w/h).toFixed(3) ) + ")";
                } else {
                    resVal.textContent = "无法读取（图片可能未加载或跨域）";
                    ratioVal.textContent = "-";
                }
            }

            // 如果图片已经加载完成（缓存情况）
            if (img.complete) {
                updateMeta();
            } else {
                img.onload = updateMeta;
                img.onerror = function () {
                    resVal.textContent = "加载失败";
                    ratioVal.textContent = "-";
                };
            }
        })();
    </script>
</div>
`;

// 模板需要两个变量：imgSrc（img 的实际 src），base64Text（textarea 内容）
pm.visualizer.set(template, {
    imgSrc: imgSrc,
    base64Text: cleanedBase64 || "" // 如果没有 base64，就置空，模板会展示相应提示
});
